import{_ as t,o as i,c as o,a2 as a}from"./chunks/framework.B72_uj9U.js";const f=JSON.parse('{"title":"Chapter 5: File Operations Tools","description":"Implement the read, write, and edit tools that give your coding agent the ability to work with files on disk.","frontmatter":{"title":"Chapter 5: File Operations Tools","description":"Implement the read, write, and edit tools that give your coding agent the ability to work with files on disk."},"headers":[],"relativePath":"learn/project/05-file-operations-tools/index.md","filePath":"learn/project/05-file-operations-tools/index.md"}'),l={name:"learn/project/05-file-operations-tools/index.md"};function r(s,e,n,h,d,c){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="file-operations-tools" tabindex="-1">File Operations Tools <a class="header-anchor" href="#file-operations-tools" aria-label="Permalink to &quot;File Operations Tools&quot;">​</a></h1><p>This chapter builds the three most important tools a coding agent can have: the ability to read files, write new files, and edit existing files. These are the tools that transform your agent from a conversationalist into something that can actually modify code. Every real-world coding agent -- Claude Code, Cursor, Aider -- has some version of these three tools at its core.</p><p>You will implement each tool as a struct that satisfies the Tool trait from Chapter 4, with proper JSON schemas, input validation, and error handling. But the engineering challenges go beyond just reading and writing bytes. You need to handle path resolution and safety checks to prevent the agent from escaping its allowed directories. You need atomic writes so a crash mid-write does not corrupt a file. You need the edit tool to perform precise string replacements without accidentally modifying the wrong section of a file.</p><p>By the end of this chapter your agent can read any file in the project, create new files, and make targeted edits to existing code. Combined with the agentic loop from Chapter 3, this means the model can now read a file, reason about what to change, make the edit, read the file again to verify, and iterate -- exactly the workflow a human developer follows.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Implement a ReadFile tool that returns file contents with line numbers</li><li>Implement a WriteFile tool with atomic writes and backup support</li><li>Implement an EditFile tool that performs exact string replacement</li><li>Handle path resolution, canonicalization, and directory traversal prevention</li><li>Test file tools thoroughly using temporary directories and fixtures</li><li>Understand the security and safety considerations of giving an agent file system access</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/05-file-operations-tools/01-read-tool.html">Read Tool</a></li><li><a href="/project/05-file-operations-tools/02-write-tool.html">Write Tool</a></li><li><a href="/project/05-file-operations-tools/03-edit-tool-string-replace.html">Edit Tool String Replace</a></li><li><a href="/project/05-file-operations-tools/04-path-handling.html">Path Handling</a></li><li><a href="/project/05-file-operations-tools/05-safety-checks.html">Safety Checks</a></li><li><a href="/project/05-file-operations-tools/06-file-permissions.html">File Permissions</a></li><li><a href="/project/05-file-operations-tools/07-diffing-strategies.html">Diffing Strategies</a></li><li><a href="/project/05-file-operations-tools/08-atomic-writes.html">Atomic Writes</a></li><li><a href="/project/05-file-operations-tools/09-glob-patterns.html">Glob Patterns</a></li><li><a href="/project/05-file-operations-tools/10-handling-large-files.html">Handling Large Files</a></li><li><a href="/project/05-file-operations-tools/11-testing-file-tools.html">Testing File Tools</a></li><li><a href="/project/05-file-operations-tools/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 4 completed (working tool system with trait, registry, and dispatch)</li><li>Understanding of Rust&#39;s std::fs module and path handling</li></ul>',10)])])}const m=t(l,[["render",r]]);export{f as __pageData,m as default};
